ucs.sentinel_kql:
// APT37 RoKRAT cloud-storage C2 — DNS lookups to pCloud/Yandex/Dropbox/Box APIs from hosts where there is no legit cloud-sync client installed
let _cloud_c2_hosts = dynamic([
    "api.pcloud.com","eapi.pcloud.com",
    "cloud-api.yandex.net","webdav.yandex.com","webdav.yandex.ru",
    "content.dropboxapi.com","api.dropboxapi.com","api-content.dropbox.com",
    "api.box.com","upload.box.com"
  ]);
let _suspect_dns = DnsEvents
    | where TimeGenerated > ago(14d)
    | where tolower(Name) in (_cloud_c2_hosts)
    | summarize Lookups = count(), FirstSeen = min(TimeGenerated), LastSeen = max(TimeGenerated)
              by ClientIP, Name;
// Correlate with a non-browser / non-sync 4688 process create on the same host within 5 minutes
let _legit_clients = dynamic(["chrome.exe","msedge.exe","firefox.exe","brave.exe","iexplore.exe","opera.exe",
    "outlook.exe","teams.exe","onedrive.exe","dropbox.exe","pcloud.exe","yandexdisk.exe","box.exe","boxdrive.exe"]);
let _proc = SecurityEvent
    | where TimeGenerated > ago(14d)
    | where EventID == 4688
    | extend ProcLeaf = tolower(tostring(split(NewProcessName, "\\")[-1]))
    | where ProcLeaf !in (_legit_clients)
    | where AccountType == "User" and Account !endswith "$";
_suspect_dns
| join kind=inner (_proc | project ProcTime = TimeGenerated, Computer, Account, NewProcessName, CommandLine, ProcLeaf) on $left.ClientIP == $right.Computer
| where ProcTime between (FirstSeen - 5m .. LastSeen + 5m)
| project FirstSeen, LastSeen, Computer, Account, Name, Lookups, ProcLeaf, NewProcessName, CommandLine
| order by FirstSeen desc
